parameters.jsCode:
const body = $('Webhook').first().json.body || {};

const validSentiments = new Set(['frustrated', 'neutral', 'happy']);
const validCategories = new Set(['technical', 'billing', 'feedback', 'other']);
const validPriorities = new Set(['low', 'medium', 'high']);
const fallbackDraft = 'Thank you for contacting SupportIQ. We received your ticket and a support agent will follow up shortly.';

const asObject = (value) => {
  if (!value) return null;
  if (typeof value === 'object') return value;
  if (typeof value === 'string') {
    try { return JSON.parse(value); } catch { return null; }
  }
  return null;
};

const candidates = [
  asObject($json?.body),
  asObject($json?.data),
  asObject($json?.response),
  asObject($json),
].filter(Boolean);

const payload =
  candidates.find((p) => p?.choices || p?.candidates || p?.error || p?.errors || p?.message) ||
  candidates[0] ||
  {};

const choiceContent = payload?.choices?.[0]?.message?.content;
const contentFromArray = Array.isArray(choiceContent)
  ? choiceContent.map((part) => (typeof part?.text === 'string' ? part.text : '')).filter(Boolean).join('\n')
  : null;

const aiText =
  (typeof choiceContent === 'string' ? choiceContent : null) ||
  contentFromArray ||
  (typeof payload?.choices?.[0]?.text === 'string' ? payload.choices[0].text : null) ||
  (typeof payload?.candidates?.[0]?.content?.parts?.[0]?.text === 'string' ? payload.candidates[0].content.parts[0].text : null) ||
  '';

const statusCodeRaw = Number(payload?.statusCode ?? payload?.status ?? $json?.statusCode ?? $json?.status ?? NaN);
const statusCode = Number.isFinite(statusCodeRaw) ? statusCodeRaw : null;

let upstreamError =
  payload?.error?.message ||
  payload?.error ||
  payload?.message ||
  (Array.isArray(payload?.errors) && (payload.errors[0]?.message || payload.errors[0])) ||
  $json?.error?.message ||
  $json?.error ||
  $json?.message ||
  (Array.isArray($json?.errors) && ($json.errors[0]?.message || $json.errors[0])) ||
  null;

if (!upstreamError && statusCode !== null && statusCode >= 400) {
  upstreamError = `AI request failed with status ${statusCode}.`;
}

let raw = typeof aiText === 'string' ? aiText : JSON.stringify(aiText ?? {});
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed = null;
if (!upstreamError && raw) {
  try { parsed = JSON.parse(raw); } catch { parsed = null; }
}

const normalizeEnum = (value, allowed, fallback) => {
  const v = typeof value === 'string' ? value.toLowerCase().trim() : '';
  return allowed.has(v) ? v : fallback;
};

const text = String(body.message || '').trim();
const textLc = text.toLowerCase();

const inferCategory = () => {
  if (/(charge|refund|invoice|payment|billing|subscription|credit card|price)/.test(textLc)) return 'billing';
  if (/(bug|error|crash|login|not working|unable|fail|issue|technical|down|outage)/.test(textLc)) return 'technical';
  if (/(suggest|feedback|feature|idea|love|great|enjoy|thanks|appreciate)/.test(textLc)) return 'feedback';
  return 'other';
};

const inferSentiment = () => {
  if (/(angry|frustrat|urgent|terrible|hate|worst|blocked|can't|cannot|not working)/.test(textLc)) return 'frustrated';
  if (/(great|love|awesome|thanks|appreciate|happy|enjoy)/.test(textLc)) return 'happy';
  return 'neutral';
};

const inferPriority = (category, sentiment) => {
  if (/(urgent|asap|immediately|critical|down|outage|blocked|cannot|can't)/.test(textLc)) return 'high';
  if (category === 'billing') return 'medium';
  if (category === 'feedback' || sentiment === 'happy') return 'low';
  return 'medium';
};

const makeDraft = (category, sentiment) => {
  const firstName = String(body.firstName || 'there').trim() || 'there';
  if (category === 'feedback') {
    return `Thank you for your feedback, ${firstName}. We appreciate your suggestion and have shared it with our product team. We are actively reviewing opportunities to improve performance and usability. If you have more ideas, please reply to this email and we will include them in our review.`;
  }
  if (category === 'billing') {
    return `Thanks for contacting SupportIQ, ${firstName}. We received your billing concern and routed it to a support specialist for review. Please share any invoice IDs or charge timestamps so we can investigate and follow up accurately.`;
  }
  if (category === 'technical') {
    return `Thanks for reporting this, ${firstName}. We understand the issue is affecting your workflow and our team is investigating. Please share any error text, screenshots, and the time it occurred so we can isolate the root cause and provide the next action.`;
  }
  return sentiment === 'happy'
    ? `Thanks for reaching out, ${firstName}. We appreciate your message and are glad to hear your experience. If you want to share additional details or suggestions, we are happy to pass them to the team.`
    : fallbackDraft;
};

const fallbackCategory = inferCategory();
const fallbackSentiment = inferSentiment();
const fallbackPriority = inferPriority(fallbackCategory, fallbackSentiment);

const sentiment = normalizeEnum(parsed?.sentiment, validSentiments, fallbackSentiment);
const category = normalizeEnum(parsed?.category, validCategories, fallbackCategory);
const priority = normalizeEnum(parsed?.priority, validPriorities, fallbackPriority);

const confidenceRaw = Number(parsed?.confidence);
const confidence = Number.isFinite(confidenceRaw)
  ? Math.max(0, Math.min(100, Math.round(confidenceRaw)))
  : (upstreamError ? 0 : 78);

const draft_response =
  typeof parsed?.draft_response === 'string' && parsed.draft_response.trim()
    ? parsed.draft_response.trim()
    : makeDraft(category, sentiment);

const hardFailure = Boolean(upstreamError);

const needsHuman =
  hardFailure ||
  priority === 'high' ||
  confidence < 85 ||
  category === 'billing';

return [
  {
    json: {
      ticket_id: body.ticketId || null,
      first_name: body.firstName || '',
      last_name: body.lastName || '',
      email: body.email || '',
      message: body.message || '',
      sentiment,
      category,
      priority,
      confidence,
      draft_response,
      parse_failed: !parsed,
      route_action: needsHuman ? 'needs_human' : 'auto_send',
      status: needsHuman ? 'needs_human' : 'ai_ready',
      auto_sent: false,
      responded_at: null,
      final_response: null,
      email_error: null,
      ai_error: hardFailure ? String(upstreamError) : null,
      raw_model_output: raw || '{}'
    }
  }
];

const analysis = $items('Build AI Analysis + Policy', 0, 0)?.[0]?.json || {};
const emailResult = $json ?? null;

const asString = typeof emailResult === 'string'
  ? emailResult
  : (typeof emailResult?.body === 'string' ? emailResult.body : '');

const statusCodeRaw = Number(
  emailResult?.statusCode ??
  emailResult?.status ??
  emailResult?.code ??
  NaN
);
const statusCode = Number.isFinite(statusCodeRaw) ? statusCodeRaw : null;

const explicitError =
  emailResult?.error?.message ||
  emailResult?.error ||
  emailResult?.message ||
  null;

const normalizedBody = asString.trim().toLowerCase();
const bodyLooksOk = normalizedBody === 'ok' || normalizedBody === 'success';
const has2xx = statusCode !== null && statusCode >= 200 && statusCode < 300;
const explicitSuccess =
  emailResult?.ok === true ||
  emailResult?.success === true ||
  emailResult?.status === 'OK' ||
  emailResult?.statusText === 'OK';

// n8n HTTP Request with continueOnFail usually exposes explicit error details on failure.
// If we have no explicit error, treat it as success to avoid false negatives from body shape differences.
const hasAnyErrorSignal = Boolean(explicitError) || (statusCode !== null && statusCode >= 400);
const isSuccess = !hasAnyErrorSignal || bodyLooksOk || has2xx || explicitSuccess;

if (!isSuccess) {
  const fallbackError =
    explicitError ||
    (statusCode !== null ? `Email send failed (${statusCode})` : null) ||
    (asString ? `Email send failed (${asString.slice(0, 140)})` : null) ||
    'Email send failed: no success acknowledgment from EmailJS.';

  return [
    {
      json: {
        ...analysis,
        route_action: 'needs_human',
        status: 'needs_human',
        auto_sent: false,
        responded_at: null,
        final_response: null,
        email_error: fallbackError
      }
    }
  ];
}

return [
  {
    json: {
      ...analysis,
      route_action: 'auto_send',
      status: 'responded',
      auto_sent: true,
      responded_at: new Date().toISOString(),
      final_response: analysis.draft_response || '',
      email_error: null
    }
  }
];

const analysis = $json || {};
return [
  {
    json: {
      ...analysis,
      route_action: 'needs_human',
      status: 'needs_human',
      auto_sent: false,
      responded_at: null,
      final_response: null,
      email_error: analysis.email_error || null
    }
  }
];
